class _SheetHarness {
  ExportSheetSubmission? submission;
}

void main() {
  Future<_SheetHarness> pumpSheet(
    WidgetTester tester, {
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = _SheetHarness();
    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  harness.submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: initialOptions,
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );
    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    return harness;
  }

  Future<ExportSheetSubmission?> pumpSheetAndSubmit(
    WidgetTester tester, {
    required Finder submitButton,
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = await pumpSheet(
      tester,
      initialOptions: initialOptions,
    );
    await tester.tap(submitButton);
    await tester.pumpAndSettle();
    return harness.submission;
  }

  testWidgets('save action triggers saveOnly export action', (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
    );

    expect(submission?.action, ExportAction.saveOnly);
  });

  testWidgets('share action triggers saveAndShare export action',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportShareButton')),
    );

    expect(submission?.action, ExportAction.saveAndShare);
  });

  testWidgets('custom resolution export includes default dimensions',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
      initialOptions: const ExportOptions(resolution: ExportResolution.custom),
    );

    expect(submission, isNotNull);
    expect(submission!.options.resolution, ExportResolution.custom);
    expect(submission.options.customWidth, 1920);
    expect(submission.options.customHeight, 1080);
  });

  testWidgets('custom fields remain export source after preset round-trip',
      (tester) async {
    tester.view.physicalSize = const Size(800, 1200);
    tester.view.devicePixelRatio = 1;
    addTearDown(tester.view.reset);

    final harness = await pumpSheet(
      tester,
      initialOptions: const ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 333,
        customHeight: 444,
      ),
    );

    await tester.tap(find.text('Customize').last);
    await tester.pumpAndSettle();

    await tester.tap(find.text('Web'));
    await tester.pumpAndSettle();

    await tester.tap(find.text(ExportResolution.custom.displayName));
    await tester.pumpAndSettle();

    expect(find.widgetWithText(TextField, '333'), findsOneWidget);
    expect(find.widgetWithText(TextField, '444'), findsOneWidget);

    await tester.tap(find.byKey(const ValueKey('exportSaveButton')));
    await tester.pumpAndSettle();

    expect(harness.submission, isNotNull);
    expect(harness.submission!.options.resolution, ExportResolution.custom);
    expect(harness.submission!.options.customWidth, 333);
    expect(harness.submission!.options.customHeight, 444);
  });

  testWidgets('sheet helper returns null when dismissed', (tester) async {
    ExportSheetSubmission? submission;

    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: const ExportOptions(),
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );

    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    await tester.tapAt(const Offset(20, 20));
    await tester.pumpAndSettle();

    expect(submission, isNull);
  });
}

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import 'package:vector_math/vector_math.dart' as vm;
import '../../core/modules/fractal_module.dart';
import '../renderer/providers/fractal_provider.dart';

/// A minimap overlay showing the current viewport position within a fractal.
class FractalMiniMap extends StatelessWidget {
  final Size viewportSize;
  final double size;
  final bool show3DIndicator;

  const FractalMiniMap({
    super.key,
    required this.viewportSize,
    this.size = 120,
    this.show3DIndicator = true,
  });

  @override
  Widget build(BuildContext context) {
    return Consumer<FractalController>(
      builder: (context, controller, _) {
        final viewState = controller.view;
        final is3D = controller.module.dimension == FractalDimension.threeD;

        if (is3D && show3DIndicator) {
          // For 3D fractals, show zoom indicator only
          return _ZoomIndicator(zoom: viewState.zoom);
        }

        return GestureDetector(
          onTapDown: (details) => _handleTap(context, controller, details.localPosition),
          onPanUpdate: (details) => _handleTap(context, controller, details.localPosition),
          child: Container(
            width: size,
            height: size,
            decoration: BoxDecoration(
              color: Colors.black54,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.white24),
            ),
            child: Stack(
              children: [
                // Grid lines
                CustomPaint(
                  size: Size(size, size),
                  painter: _GridPainter(),
                ),
                // Viewport rectangle
                CustomPaint(
                  size: Size(size, size),
                  painter: _ViewportPainter(
                    pan: Offset(viewState.pan.x, viewState.pan.y),
                    zoom: viewState.zoom,
                    viewportSize: viewportSize,
                  ),
                ),
                // Center dot
                Center(
                  child: Container(
                    width: 6,
                    height: 6,
                    decoration: BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                      border: Border.all(color: Colors.white, width: 1),
                    ),
                  ),
                ),
                // Zoom indicator
                Positioned(
                  bottom: 4,
                  left: 0,
                  right: 0,
                  child: _ZoomPill(zoom: viewState.zoom),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  void _handleTap(BuildContext context, FractalController controller, Offset localPosition) {
    // Convert tap position to fractal coordinates
    final normalizedX = (localPosition.dx / size) - 0.5;
    final normalizedY = (localPosition.dy / size) - 0.5;

    // Scale by some reasonable factor based on current zoom
    final scale = 2.0 / controller.view.zoom;
    final newPan = vm.Vector2(normalizedX * scale, normalizedY * scale);

    controller.updatePan(newPan);
  }
}

class _ZoomIndicator extends StatelessWidget {
  final double zoom;
  const _ZoomIndicator({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: Colors.black54,
        borderRadius: BorderRadius.circular(16),
      ),
      child: Text(
        'Zoom: ${zoom.toStringAsFixed(1)}×',
        style: const TextStyle(color: Colors.white, fontSize: 12),
      ),
    );
  }
}

class _ZoomPill extends StatelessWidget {
  final double zoom;
  const _ZoomPill({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        decoration: BoxDecoration(
          color: Colors.black87,
          borderRadius: BorderRadius.circular(8),
        ),
        child: Text(
          '${zoom.toStringAsFixed(0)}×',
          style: const TextStyle(color: Colors.white70, fontSize: 10),
        ),
      ),
    );
  }
}

class _GridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 0.5;

    // Draw grid
    for (var i = 1; i < 4; i++) {
      final x = size.width * i / 4;
      final y = size.height * i / 4;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

class _ViewportPainter extends CustomPainter {
  final Offset pan;
  final double zoom;
  final Size viewportSize;

  _ViewportPainter({
    required this.pan,
    required this.zoom,
    required this.viewportSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.cyan
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2;

    // Calculate viewport rectangle
    // The viewport in fractal space is roughly 2/zoom wide (for a -1 to 1 base range)
    final viewportWidth = (2.0 / zoom) * (size.width / 4);
    final viewportHeight = (2.0 / zoom) * (size.height / 4);

    // Pan offset
    final centerX = size.width / 2 + pan.dx * size.width / 4;
    final centerY = size.height / 2 + pan.dy * size.height / 4;

    final rect = Rect.fromCenter(
      center: Offset(centerX, centerY),
      width: viewportWidth.clamp(4.0, size.width),
      height: viewportHeight.clamp(4.0, size.height),
    );

    canvas.drawRect(rect, paint);
  }

  @override
  bool shouldRepaint(covariant _ViewportPainter oldDelegate) {
    return pan != oldDelegate.pan || zoom != oldDelegate.zoom;
  }
}

import 'package:vector_math/vector_math.dart';

/// Represents the view/camera state for fractal rendering.
///
/// This class captures the user's navigation state within a fractal:
/// - For 2D fractals: pan offset and zoom level
/// - For 3D fractals: rotation angles and zoom level
///
/// [FractalViewState] is designed to be stored in presets and serialized,
/// allowing users to save and restore specific viewpoints.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final view = FractalViewState(
///   pan: Vector2(-0.5, 0.2),  // Offset from center
///   zoom: 3.0,                 // 3x magnification
///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 pan;

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 rotation;

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state.
  const FractalViewState({
    required this.pan,
    required this.zoom,
    required this.rotation,
  });

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : pan = Vector2.zero(),
        zoom = 1.0,
        rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? this.pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
    );
  }
}

